CREATE TABLE IF NOT EXISTS lobby_presence (id serial PRIMARY KEY, assignment_id integer REFERENCES assignments(id) ON DELETE CASCADE, username text NOT NULL, joined_at timestamptz DEFAULT now()); ALTER TABLE lobby_presence ENABLE ROW LEVEL SECURITY; CREATE POLICY "Anyone can insert lobby presence" ON lobby_presence FOR INSERT WITH CHECK (true); CREATE POLICY "Anyone can read lobby presence" ON lobby_presence FOR SELECT USING (true); CREATE POLICY "Anyone can delete lobby presence" ON lobby_presence FOR DELETE USING (true);